if (! function_exists('crypto_ticker')) {
    function crypto_ticker($coin = null, $currency = null, $timeout = null)
    {
            $coin = $coin ?? 'bitcoin';
            $currency = $currency ?? 'usd';
            $timeout = $timeout ?? 15;

            $timeout = max(5, min(30, (int)$timeout));
