            $currency = trim(strtolower($currency));

            if (empty($coin)) $coin = 'bitcoin';

            // Helper: fetch JSON
            $fetch_json = function($url, $t) {
                $ctx = stream_context_create([
                    'http' => ['method' => 'GET', 'timeout' => $t, 'header' => "User-Agent: crypto_ticker/1.0\r\n", 'ignore_errors' => true],
                    'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
                ]);
                $body = @file_get_contents($url, false, $ctx);
                if ($body === false) return ['error' => error_get_last()['message'] ?? 'fetch failed', 'success' => false];
                $status = 200;
                if (isset($http_response_header)) {
                    foreach ($http_response_header as $h) {
                        if (preg_match('#^HTTP/\d+\.\d+ (\d+)#', $h, $m)) { $status = (int)$m[1]; break; }
                    }
                }
                if ($status === 429) return ['error' => 'Rate limited (429) — CoinGecko API has request limits.', 'success' => false];
                if ($status === 404) return ['error' => 'Coin not found (404)', 'success' => false];
                if ($status >= 400) return ['error' => "HTTP $status", 'success' => false];
                $data = @json_decode($body, true);
                if ($data === null) return ['error' => 'Invalid JSON', 'success' => false];
                return ['data' => $data, 'status' => $status, 'success' => true];
            };

            // CoinGecko API — get coin data (includes market data, description, links)
            $api_url = "https://api.coingecko.com/api/v3/coins/{$coin}?localization=false&tickers=false&community_data=false&developer_data=false";
            $result = $fetch_json($api_url, $timeout);

            if (!$result['success']) {
                // Try simpler price endpoint as fallback
                $simple_url = "https://api.coingecko.com/api/v3/simple/price?ids={$coin}&vs_currencies={$currency}&include_24hr_vol=true&include_24hr_change=true&include_market_cap=true";
                $simple = $fetch_json($simple_url, $timeout);
                if (!$simple['success']) {
                    return [
                        'success' => false,
                        'error' => 'CoinGecko API: ' . $result['error'],
                        'coin' => $coin,
                    ];
                }
                $sd = $simple['data'];
                if (!isset($sd[$coin])) {
                    return [
                        'success' => false,
                        'error' => "Coin '$coin' not found on CoinGecko. Try a different ID (e.g. 'bitcoin', 'ethereum', 'cardano').",
