                    'data_quality' => 'minimal',
                ];
            }

            $data = $result['data'];

            // Extract market data
            $market = $data['market_data'] ?? [];

            if (empty($market)) {
                return [
                    'success' => false,
                    'error' => "Market data not available for '$coin'.",
                    'coin' => $coin,
                ];
            }

            // Price in requested currency
            $current_price = $market['current_price'][$currency] ?? null;
