            // Price changes
            $change_24h = $market['price_change_percentage_24h'] ?? null;
            $change_7d = $market['price_change_percentage_7d'] ?? null;
            $change_30d = $market['price_change_percentage_30d'] ?? null;
            $change_1y = $market['price_change_percentage_1y'] ?? null;

            // Supply data
            $circulating_supply = $market['circulating_supply'] ?? null;
            $total_supply = $market['total_supply'] ?? null;
            $max_supply = $market['max_supply'] ?? null;

            // Coin metadata
            $name = $data['name'] ?? ucfirst($coin);
            $symbol = strtoupper($data['symbol'] ?? $coin);
            $description = $data['description']['en'] ?? '';
            $description = strip_tags($description);
            if (strlen($description) > 500) $description = substr($description, 0, 500) . '...';
            $homepage = $data['links']['homepage'][0] ?? '';
            $image = $data['image']['small'] ?? '';
            $genesis_date = $data['genesis_date'] ?? null;
            $categories = $data['categories'] ?? [];
            $coingecko_rank = $data['coingecko_rank'] ?? null;
